import React, { useState, useEffect } from 'react';

function Doctor() {
  const [lang, setLang] = useState('en');
  const [day, setDay] = useState(new Date().toISOString().slice(0, 10));
  const [patients, setPatients] = useState([]);

  const texts = {
    en: ["Doctor Dashboard", "Day:", "Load Patients", "Call Next", "Switch Language"],
    ru: ["Панель врача", "День:", "Загрузить пациентов", "Следующий", "Сменить язык"],
    kg: ["Дарыгер панели", "Күн:", "Пациенттерди жүктөө", "Кийинкиси", "Тилди өзгөртүү"]
  };

  const switchLanguage = () => {
    setLang(lang === "en" ? "ru" : lang === "ru" ? "kg" : "en");
  };

  const loadPatients = async () => {
    try {
      const response = await fetch(`/api/patients?day=${day}`);
      const patientsData = await response.json();
      patientsData.sort((a, b) => a.time.localeCompare(b.time));
      setPatients(patientsData);
    } catch (err) {
      console.error('Failed to load patients:', err);
    }
  };

  const callNext = async () => {
    try {
      await fetch('/api/call-next', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ day })
      });
      loadPatients();
    } catch (err) {
      console.error('Failed to call next patient:', err);
    }
  };

  useEffect(() => {
    loadPatients();
    const interval = setInterval(loadPatients, 3000);
    return () => clearInterval(interval);
  }, [day]);

  const t = texts[lang];

  return (
    <div className="container">
      <h2>{t[0]}</h2>

      <label>{t[1]}</label>
      <input
        type="date"
        value={day}
        onChange={(e) => setDay(e.target.value)}
      /><br />

      <button onClick={loadPatients}>{t[2]}</button>
      <button onClick={callNext}>{t[3]}</button>
      <button onClick={switchLanguage} className="lang">{t[4]}</button>

      <div>
        {patients.map(patient => (
          <div key={patient.id} className={`card status-${patient.status.replace(/\s/g, '')}`}>
            <strong>{patient.name}</strong><br />
            Department: {patient.department}<br />
            Time: {patient.time}<br />
            Queue #: {patient.queueNumber}<br />
            Status: {patient.status}
          </div>
        ))}
      </div>
    </div>
  );
}

export default Doctor;
